var shell = require('shelljs');
var fs = require('fs');
var path = require('path');
var grunt = require('grunt');
var task = require('./task/main');
var gruntfile = require('./gruntfile');
var _ = require('underscore');

var build = function(settings){
	var $ = {};
	$.printLog = settings.printLog;
	$.process = settings.process;
	$.done = settings.done;
	$.options = null;

	//重写grunt日志输出函数
	grunt.log.__proto__._write = function(msg) {
	  // Abort if muted.
	  if (this.muted) { return; }
	  // Actually write output.
	  this.hasLogged = true;
	  msg = msg || '';
	  //过滤掉颜色代码
	  msg = ("" + msg).replace(/\x1B\[\d+m/g, '');
	  //打印日志到控制台
	  $.printLog(msg);
	};

	$.start = function(params){
		$.options = params;
		var root = params.root;
		var tmp = $.options.tmp = path.resolve(root,(params.tmp+'_'+new Date().getTime()+""));
		$.options.clear = params.clear!=undefined? params.clear : true;
		$.options.delay = params.delay || 150;//每延时150ms启动一个构建任务
		var inf = params.inf;
		var outf = params.outf;
		var queue = params.queue;
		
		$.delay = settings.delay || 150;//s
		$.printLog('# 基础目录：',root);
		$.printLog('# 构建目录：',inf);
		$.printLog('# 输出目录：',outf);
		$.printLog('# 临时目录：',tmp);
		$.printLog('# 待构建队列：',queue);
		//进入项目根目录
		shell.cd(root);

		//创建临时目录
		if(!fs.existsSync(tmp)){
			shell.mkdir('-p',tmp);
			$.printLog('> 创建了临时目录。');
		}else{
			shell.rm('-rf',tmp+'/*');
		}
		//拷贝待构建文件到临时文件夹中
		var cps = queue.map(function(name){
			return inf+'/'+name;
		});
		shell.cp('-rf',cps,$.options.tmp);
		$.printLog('> 待构建文件已拷贝到临时文件夹中。');
		
		//生成gruntfile配置文件，放入临时文件夹下
		var gfPath = gruntfile(grunt,$.options);
		$.printLog('# Gruntfile:',gfPath);
		$.printLog('-------------任务开始-----------');
		//启动任务
		$.run(queue,gfPath);
	}

	$.run = function(queue,gfPath){
		if(queue.length>0){
			var name = queue.shift();
			var curr = path.join($.options.tmp,name);
			grunt.tasks([],{
				verbose: $.options.moreLog,
				base: curr,
				gruntfile: gfPath
			},function(){
				$.process?$.process(name):$.printLog(name,'已构建。。。');
				setTimeout(function(){
					shell.cd(path.resolve($.options.root));
					$.run(queue,gfPath);
				},$.options.delay);
			});
		}else{
			//清空临时文件
			if($.options.clear && ($.options.clear==undefined || $.options.clear==true ) ){
				shell.rm('-rf',$.options.tmp);
				$.printLog('# 临时目录已删除！');	
			}else{
				$.printLog('# 临时目录设置为不删除！请查看：',$.options.tmp);
			}
			if($.done){
				$.done(shell);
			}else{
				$.printLog('##构建任务完成。。。');
				$.printLog('-------------任务结束-----------');
			}
		}
	}

	/**
	获取inf文件夹下的所有可构建组建集合，
	如果获取成功，则调用callback，并将获取到的数组集合作为第二个参数传递给callback，
	如果callback的第一个参数存在则获取失败
	**/
	$.getQueue = function(inf,callback){
		fs.exists(inf,function(exists){
			if(!exists){
				callback('构建目录不存在！！！');
				return;
			}
			fs.readdir(inf,function(err, files){
				if(err){
					callback('读取文件夹错误。');
					return;
				}
				var size = files.length;
				var queue = [];
				files.forEach(function(file,i){
					fs.stat(path.join(inf,file),function(err,stats){
						if(err){
							callback('读取文件状态信息错误。');
							return;
						}
						if(stats && stats.isDirectory() && fs.existsSync(path.join(inf,file,'package.json')) ){
							queue.push(file);
						}
						if(i==size-1){
							callback(null,queue);
						}
					});
				});
			});
		});
	}
	return $;
};

module.exports = build;